#!/usr/bin/env bash
set -euo pipefail

BASE="https://raw.githubusercontent.com/gear66me-ui/GitHub_Sandbox/main"
TARGET="${1:-NASA_SDO_2012_TRACK_EXTRACT.py}"
OLD_SHA="1f8546af02e34668f965bfdb17c0a442cf6c78afa0e7af031228bd1e4eb25967"
NEW_SHA="d8b40428c2bb1bf2744049de621fb788cd893fd91e465463ac4996963efaac65"

curl -fsSL --retry 3 "$BASE/NASA_SDO_2012_TRACK_EXTRACT_DOWNLOAD.sh" | bash -s -- "$TARGET"
ACTUAL_OLD="$(sha256sum "$TARGET" | awk '{print $1}')"
[[ "$ACTUAL_OLD" == "$OLD_SHA" ]] || { echo "Base SHA mismatch" >&2; exit 1; }

PATCH_B64=''
printf '%s' "$PATCH_B64" | base64 -d | gzip -d > NASA_SDO_2012_V0002.patch
patch --silent "$TARGET" NASA_SDO_2012_V0002.patch
rm -f NASA_SDO_2012_V0002.patch

ACTUAL_NEW="$(sha256sum "$TARGET" | awk '{print $1}')"
[[ "$ACTUAL_NEW" == "$NEW_SHA" ]] || {
  echo "V0002 SHA-256 verification failed." >&2
  echo "Expected: $NEW_SHA" >&2
  echo "Actual  : $ACTUAL_NEW" >&2
  exit 1
}
python -m py_compile "$TARGET"
printf 'Downloaded and verified: %s\n' "$TARGET"
printf 'Version: V0002\n'
printf 'SHA-256: %s\n' "$ACTUAL_NEW"
